                    writer.WriteString("icon", serviceItem.Icon);
                else
                    writer.WriteNull("icon");

            if (serviceItem.ValueDefaultsOption.IsSet)
                if (serviceItem.ValueDefaultsOption.Value != null)
                    writer.WriteString("valueDefaults", serviceItem.ValueDefaults);
                else
                    writer.WriteNull("valueDefaults");

            if (serviceItem.DescriptionOption.IsSet)
                if (serviceItem.DescriptionOption.Value != null)
                    writer.WriteString("description", serviceItem.Description);
                else
                    writer.WriteNull("description");

            if (serviceItem.TagsOption.IsSet)
                if (serviceItem.TagsOption.Value != null)
                    writer.WriteString("tags", serviceItem.Tags);
                else
                    writer.WriteNull("tags");

            if (serviceItem.IsSystemOption.IsSet)
                writer.WriteBoolean("isSystem", serviceItem.IsSystemOption.Value.Value);

            if (serviceItem.ShowOption.IsSet)
                writer.WriteBoolean("show", serviceItem.ShowOption.Value.Value);

            if (serviceItem.ShowIndexOption.IsSet)
                writer.WriteNumber("showIndex", serviceItem.ShowIndexOption.Value.Value);

            if (serviceItem.CreateDateOption.IsSet)
                writer.WriteString("createDate", serviceItem.CreateDateOption.Value.Value.ToString(CreateDateFormat));

            if (serviceItem.LastUpdateOption.IsSet)
                writer.WriteString("lastUpdate", serviceItem.LastUpdateOption.Value.Value.ToString(LastUpdateFormat));
        }
    }
}
